class Solution {
    public List<List<Integer>> pacificAtlanticWaterFlow(int[][] data) {
        List<List<Integer>> result = new ArrayList<>();
        if (data == null || data.length == 0 || data[0].length == 0) {
            return result;
        }
        int rows = data.length;
        int cols = data[0].length;
        boolean[][] pacific = new boolean[rows][cols];
        boolean[][] atlantic = new boolean[rows][cols];
        for (int i = 0; i < rows; i++) {
            dfs(data, pacific, i, 0); // Pacific
            dfs(data, atlantic, i, cols - 1); // Atlantic
        }
        for (int j = 0; j < cols; j++) {
            dfs(data, pacific, 0, j); // Pacific
            dfs(data, atlantic, rows - 1, j); // Atlantic
        }
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                if (pacific[i][j] && atlantic[i][j]) {
                    List<Integer> cell = new ArrayList<>();
                    cell.add(i);
                    cell.add(j);
                    result.add(cell);
                }
            }
        }
        return result;
    }
    private void dfs(int[][] data, boolean[][] ocean, int row, int col) {
        ocean[row][col] = true;
        int[][] directions = {
            {
                0, 1
            }
            , {
                1, 0
            }
            , {
                0, -1
            }
            , {
                -1, 0
            }
        }
        ;
        for (int[] dir : directions) {
            int newRow = row + dir[0];
            int newCol = col + dir[1];
            if (newRow >= 0 && newRow < data.length && newCol >= 0 && newCol < data[0].length
            && !ocean[newRow][newCol] && data[newRow][newCol] >= data[row][col]) {
                dfs(data, ocean, newRow, newCol);
            }
        }
    }
}

