package main

import "fmt"

func pacificAtlanticWaterFlow(data [][]int) [][]int {
    if len(data) == 0 || len(data[0]) == 0 {
        return [][]int{}
    }

    rows, cols := len(data), len(data[0])
    pacific := make([][]bool, rows)
    atlantic := make([][]bool, rows)
    for i := range pacific {
        pacific[i] = make([]bool, cols)
        atlantic[i] = make([]bool, cols)
    }

    var dfs func(r, c int, visited [][]bool, prevHeight int)
    dfs = func(r, c int, visited [][]bool, prevHeight int) {
        if r < 0 || c < 0 || r >= rows || c >= cols || visited[r][c] || data[r][c] < prevHeight {
            return
        }
        visited[r][c] = true
        dfs(r+1, c, visited, data[r][c])
        dfs(r-1, c, visited, data[r][c])
        dfs(r, c+1, visited, data[r][c])
        dfs(r, c-1, visited, data[r][c])
    }

    for i := 0; i < rows; i++ {
        dfs(i, 0, pacific, data[i][0])      // Pacific edge
        dfs(i, cols-1, atlantic, data[i][cols-1]) // Atlantic edge
    }
    for j := 0; j < cols; j++ {
        dfs(0, j, pacific, data[0][j])      // Pacific edge
        dfs(rows-1, j, atlantic, data[rows-1][j]) // Atlantic edge
    }

    result := [][]int{}
    for i := 0; i < rows; i++ {
        for j := 0; j < cols; j++ {
            if pacific[i][j] && atlantic[i][j] {
                result = append(result, []int{i, j})
            }
        }
    }
    return result
}

func main() {
    data := [][]int{
        {1, 2, 2, 3, 5},
        {3, 2, 3, 4, 4},
        {2, 4, 5, 3, 2},
        {6, 7, 1, 4, 5},
        {5, 1, 1, 2, 4},
    }
    result := pacificAtlanticWaterFlow(data)
    fmt.Println(result)
}

